 84→    private String buildExecuteCacheKey(Principal principal, ControlId controlId, ControlRequestOption requestOption) {
 85→        try {
 86→            MessageDigest md = MessageDigest.getInstance("MD5");
 87→            // 逐段 update，避免拼接 ~1MB 中间字符串
 88→            md.update((principal.getPrincipalType() + ":" + principal.getPrincipal() + "|"
 89→                    + controlId.getControlType() + "|").getBytes(StandardCharsets.UTF_8));
 90→            List<String> ids = new ArrayList<>(controlId.getControlIds());
 91→            ids.sort(String::compareTo);
 92→            for (String id : ids) {
 93→                md.update(id.getBytes(StandardCharsets.UTF_8));
 94→                md.update((byte) ',');
 95→            }
 96→            String optPart = requestOption == null ? "" : requestOption.cacheKey();
 97→            md.update(("|" + optPart).getBytes(StandardCharsets.UTF_8));
 98→            return HexFormat.of().formatHex(md.digest());
 99→        } catch (NoSuchAlgorithmException e) {
100→            // MD5 is guaranteed by JVM spec, should never happen
101→            throw new IllegalStateException("MD5 not available", e);
102→        }
103→    }
