200→    public Map<Long, ControlRole> buildUserRoleMapFromCache(Long spaceNodeId, List<SpaceNodeUserRoleCacheEntity> cacheEntities) {
201→        Map<Long, ControlRole> userIdToRoleMap = new HashMap<>();
202→        if (spaceNodeId == null || CollectionUtils.isEmpty(cacheEntities)) {
203→            return userIdToRoleMap;
204→        }
205→
206→        Map<Integer, ControlRole> roleLevelToDecoratedRole = new HashMap<>();
207→        for (SpaceNodeUserRoleCacheEntity entity : cacheEntities) {
208→            if (entity == null || entity.getSpaceNodeId() == null || entity.getRoleLevel() == null) {
209→                continue;
210→            }
211→            if (!spaceNodeId.equals(entity.getSpaceNodeId())) {
212→                continue;
213→            }
214→            roleLevelToDecoratedRole.computeIfAbsent(entity.getRoleLevel(), level -> {
215→                ControlRole base = NodeRoleLevel.fromLevel(level).toControlRole();
216→                if (base == null) {
217→                    return null;
218→                }
219→                ControlRoleDict dict = ControlRoleDict.create();
220→                dict.put(spaceNodeId.toString(), base);
221→                ControlRoleDict decoratedDict = resetPermissionsBySpacePolicy(dict, ControlIdBuilder.spaceNodeIds(List.of(spaceNodeId)));
222→                return decoratedDict == null ? null : decoratedDict.get(spaceNodeId.toString());
223→            });
224→        }
225→
226→        for (SpaceNodeUserRoleCacheEntity entity : cacheEntities) {
227→            if (entity == null || entity.getUserId() == null || entity.getSpaceNodeId() == null) {
228→                continue;
229→            }
230→            if (!spaceNodeId.equals(entity.getSpaceNodeId())) {
231→                continue;
232→            }
233→            ControlRole role = roleLevelToDecoratedRole.get(entity.getRoleLevel());
234→            if (role == null) {
235→                continue;
236→            }
237→            userIdToRoleMap.put(entity.getUserId(), role);
238→        }
239→
240→        return userIdToRoleMap;
241→    }
