243→    public void mustHaveSpaceNodeRole(String role, Long userId, Long spaceNodeId) {
244→        ControlRoleDict controlRoleDict = execute(PrincipalBuilder.userId(userId), ControlIdBuilder.spaceNodeId(spaceNodeId));
245→        ControlRole needRole = ControlRoleManager.parseNodeRole(role);
246→        ControlRole selfRole = controlRoleDict.get(spaceNodeId.toString());
247→        if (selfRole != null && selfRole.isGreaterThanOrEqualTo(needRole)) {
248→            return;
249→        }
250→        throw new BusinessException(SpaceNodeException.UNAUTHORIZED);
