263→    public void mustHaveSpaceNodePermission(NodePermission permission, Long userId, Long spaceNodeId, String spaceId) {
264→        if (userId == null || permission == null) {
265→            // 这两个必须有
266→            throw new BusinessException(SpaceNodeException.UNAUTHORIZED);
267→        }
268→
269→        if (spaceId == null &&  spaceNodeId == null) {
270→            // 两者至少有一个不为null
271→            throw new BusinessException(SpaceNodeException.UNAUTHORIZED);
272→        }
273→
274→        ControlRole selfRole;
275→
276→        if (spaceNodeId == null || ROOT_PARENT_ID.equals(spaceNodeId)) {
277→            // 校验spaceId赋予该用户的默认spaceNode权限
278→            String roleTag;
279→            if (spaceQueryManager.isUserSpaceAdmin(userId, spaceId)) {
280→                roleTag = RoleConstants.SpaceNode.MANAGER;
281→            } else if (spaceQueryManager.isUserInSpace(userId, spaceId)) {
282→                roleTag = RoleConstants.SpaceNode.DEFAULT_ROLE;
283→            } else {
284→                throw new BusinessException(SpaceNodeException.UNAUTHORIZED);
285→            }
286→
287→            ControlRole userSpaceRole = ControlRoleManager.parseNodeRole(roleTag);
288→            SpacePermissionPolicy policy = spacePermissionPolicyQueryManager.getPolicyBySpaceId(ControlType.SPACE_NODE.getVal(), spaceId);
289→            selfRole = new SpacePolicyEnforcedControlRole(userSpaceRole, policy);
290→        } else {
291→            // 校验spaceNode对应的权限
292→            ControlRoleDict controlRoleDict = execute(PrincipalBuilder.userId(userId), ControlIdBuilder.spaceNodeId(spaceNodeId), ControlRequestOption.create().setRubbishRoleBuilding(true));
293→            selfRole = controlRoleDict.get(spaceNodeId.toString());
294→        }
295→
296→        if (selfRole != null && selfRole.hasPermission(permission)) {
297→            return;
298→        }
299→
300→        throw new BusinessException(SpaceNodeException.UNAUTHORIZED);
301→    }
