303→    public void mustBeSpaceAdmin(Long userId, String spaceId) {
304→        if (spaceQueryManager.isUserSpaceAdmin(userId, spaceId)) {
305→            return;
306→        }
307→        throw new BusinessException(SpaceException.UNAUTHORIZED);
308→    }
