 74→    @Override
 75→    public NodeCollaboratorsVo getNodeRoles(Long userId, String spaceId, Long spaceNodeId) {
 76→        NodeCollaboratorsVo result = new NodeCollaboratorsVo();
 77→        SpaceNodeEntity spaceNode = spaceNodeService.getById(spaceNodeId);
 78→        ExceptionUtil.isNotNull(spaceNode, SpaceNodeException.NOT_EXIST);
 79→        Long roleNodeId;
 80→        List<NodeRoleUnit> units;
 81→        // 该节点没被设置过权限时, 需要继承父节点权限, 此时extend为true
 82→        boolean extend = !controlService.existsByControlId(spaceNodeId.toString());
 83→        result.setExtend(extend);
 84→        if (extend) {
 85→            // 当前节点没有分配角色，需要向上查找父节点的角色
 86→            roleNodeId = getNodeExtendNodeId(spaceNodeId);
 87→            if (roleNodeId == null) {
 88→                // 没找到父节点, 返回空间站组的角色
 89→                units = getSpaceNodeRoleUnitList(spaceId);
 90→                result.setExtendNodeName(units.getFirst().getUnitName());
 91→            } else {
 92→                SpaceNodeEntity extendNode = spaceNodeService.getById(roleNodeId);
 93→                result.setExtendNodeName(extendNode.getName());
 94→                units = getNodeRoleUnitList(roleNodeId);
 95→            }
 96→        } else {
 97→            // 当前节点有分配角色，不需要向上查找父节点的角色
 98→            roleNodeId = spaceNodeId;
 99→            units = getNodeRoleUnitList(roleNodeId);
100→        }
101→
102→        result.setRoleUnits(units);
103→
104→        List<Long> adminIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(spaceId);
105→        // 可以考虑将toUnitMemberVos的结果复用, 减少toUnitMemberVo的调用次数
106→        result.setAdmins(nodeRoleTransfer.toUnitMemberVos(adminIds, spaceId));
107→        result.setSelf(nodeRoleTransfer.toUnitMemberVo(userId, spaceId));
108→        result.setBelongRootFolder(treeNodeTemplate.isNodeBelongRootFolder(spaceNodeId));
109→
110→        return result;
111→    }
