113→    private List<NodeRoleUnit> getSpaceNodeRoleUnitList(String spaceId) {
114→        Long rootTeamUnitId = apitableGrpcClientService.getRootTeamUnitId(spaceId);
115→        List<NodeRoleUnit> nodeRoleUnitList = apitableGrpcClientService.getNodeRoleUnitList(spaceId, List.of(rootTeamUnitId));
116→        for (NodeRoleUnit nodeRoleUnit : nodeRoleUnitList) {
117→            nodeRoleUnit.setRole(RoleConstants.SpaceNode.DEFAULT_ROLE);// space default role
118→        }
119→        return nodeRoleUnitList;
120→    }
