122→    private List<NodeRoleUnit> getNodeRoleUnitList(Long roleNodeId) {
123→        List<ControlRoleEntity> controlRoleUnits = controlRoleService.getByControlId(roleNodeId.toString());
124→        if (CollectionUtils.isEmpty(controlRoleUnits)) return List.of();
125→        return nodeRoleTransfer.toNodeRoleUnits(roleNodeId, controlRoleUnits);
126→    }
