128→    @Override
129→    public Long getNodeExtendNodeId(Long spaceNodeId) {
130→        List<NodeEntity> parentTreeNodesFromParentToRoot = treeNodeTemplate.getParentNodesByRelId(spaceNodeId);
131→        for (NodeEntity parentTreeNode : parentTreeNodesFromParentToRoot) {
132→            if (parentTreeNode.getRelId().equals(spaceNodeId)) {
133→                continue;// exclude self
134→            }
135→            Long parentSpaceNodeId = parentTreeNode.getRelId();
136→            if (controlService.existsByControlId(parentSpaceNodeId.toString())) {
137→                // first parent node has perm
138→                return parentTreeNode.getRelId();
139→            }
140→        }
141→        return null;
142→    }
