144→    @Override
145→    public List<SimpleNodeInfo> getNodeInfoWithPermissionStatus(List<Long> spaceNodeIds) {
146→        if (CollectionUtils.isEmpty(spaceNodeIds)) return List.of();
147→        List<NodeEntity> nodes = treeNodeTemplate.getParentPathNodesByRelIds(spaceNodeIds);
148→        if (CollectionUtils.isEmpty(nodes)) return List.of();
149→
150→        List<String> controlIds = nodes.stream().map(node -> String.valueOf(node.getRelId())).toList();
151→        List<ControlEntity> existedControls = controlService.getByControlIds(controlIds);
152→        List<Long> existedControlIds = CollectionUtils.isNotEmpty(existedControls)
153→                ? existedControls.stream().map(e -> Long.valueOf(e.getControlId())).toList()
154→                : List.of();
155→
156→        return nodes.stream()
157→                .map(node -> new SimpleNodeInfo(node.getId(), node.getParentId(), node.getRelId(),
158→                        !existedControlIds.contains(node.getRelId())))
159→                .toList();
160→    }
