164→        List<NodeRoleUnit> unitList = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
165→        if (Objects.equals(unitList.size(), unitIds.size())) {
166→            return;
167→        }
168→        throw new BusinessException(SpaceException.UNIT_NOT_EXIST);
