171→    @Override
172→    public ControlRoleDict getAppNodesRole(GetAppNodesRoleRo ro, Long userId) {
173→        ControlRoleDict result = ControlRoleDict.create();
174→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(ro.getAppNodeIds());
175→        if (CollectionUtils.isEmpty(spaceNodeEntities)) {
176→            return result;
177→        }
178→        List<Long> spaceNodeIds = spaceNodeEntities.stream().map(SpaceNodeEntity::getId).toList();
179→        ControlRoleDict controlRoleDict = controlTemplate.fetchSpaceNodeRole(userId, spaceNodeIds);
180→
181→        Map<String, String> idToAppSpaceNodeIdMap = spaceNodeEntities.stream()
182→                .collect(Collectors.toMap(
183→                        entity -> entity.getId().toString(),
184→                        SpaceNodeEntity::getAppSpaceNodeId
185→                ));
186→
187→        // 替换key为appSpaceNodeId
188→        for (Map.Entry<String, ControlRole> entry : controlRoleDict.entrySet()) {
189→            String id = entry.getKey();
190→            String appSpaceNodeId = idToAppSpaceNodeIdMap.get(id);
191→            if (appSpaceNodeId != null) {
192→                result.put(appSpaceNodeId, entry.getValue());
193→            }
194→        }
195→
196→        return result;
197→    }
