199→    @Override
200→    public ControlRoleDict getShareRole(String shareId, Long userId) {
201→        ControlRoleDict result = ControlRoleDict.create();
202→        if (userId == null) {
203→            log.error("getShareRole userId is null, shareId: {}", shareId);
204→            return result;
205→        } // todo user share scope
206→        NodeShareEntity nodeShareEntity = nodeShareService.getByShareId(shareId);
207→        if (nodeShareEntity == null || Boolean.FALSE.equals(nodeShareEntity.getIsEnabled())) {
208→            log.error("getShareRole nodeShareEntity is null, shareId: {}", shareId);
209→            return result;
210→        }
211→        SpaceNodeEntity spaceNodeEntity = spaceNodeService.getById(nodeShareEntity.getSpaceNodeId());
212→        if (spaceNodeEntity == null) {
213→            log.error("getShareRole spaceNodeEntity is null, spaceNodeId: {}", nodeShareEntity.getSpaceNodeId());
214→            return result;
215→        }
216→        String appSpaceNodeId = spaceNodeEntity.getAppSpaceNodeId();
217→
218→        NodeShareProps props = NodeShareProps.fromBits(nodeShareEntity.getPropsBits());
219→        if (props.getOnlyRead()) {
220→            result.put(appSpaceNodeId, new NodeReaderRole());
221→            return result;
222→        }
223→        if (props.getCanBeEdited()) {
224→            result.put(appSpaceNodeId, new NodeEditorRole());
225→            return result;
226→        }
227→        if (props.getCanBeStored()) {
228→            result.put(appSpaceNodeId, new NodeManagerRole());
229→            return result;
230→        }
231→        log.error("props not contains role, shareId: {}, props: {}", shareId, props);
232→        return result;
233→    }
