 37→    private final Cache<String, ControlRoleDict> roleDictCache = Caffeine.newBuilder()
 38→            .maximumSize(10_000)
 39→            .expireAfterWrite(Duration.ofSeconds(30))
 40→            .build();
 41→
 42→    @Override
 43→    public List<Long> listUserIdsBySpaceNodeIdsAndMinRole(List<Long> spaceNodeIds, NodeRoleLevel minRole) {
 44→        return spaceNodeUserRoleCacheService.listUserIdsByspaceNodeIdsAndMinRole(spaceNodeIds, minRole);
