 47→    @Override
 48→    public ControlRoleDict fetchSpaceNodeRoleCached(Long userId, List<Long> spaceNodeIds) {
 49→        if (userId == null || CollectionUtils.isEmpty(spaceNodeIds)) {
 50→            return ControlRoleDict.create();
 51→        }
 52→        List<Long> normalizedSpaceNodeIds = normalizeSpaceNodeIds(spaceNodeIds);
 53→        if (normalizedSpaceNodeIds.isEmpty()) {
 54→            return ControlRoleDict.create();
 55→        }
 56→        String cacheKey = buildRoleCacheKey(userId, normalizedSpaceNodeIds);
 57→        ControlRoleDict roleDict = roleDictCache.get(cacheKey, key -> loadRoleDict(userId, normalizedSpaceNodeIds));
 58→        if (roleDict == null) {
 59→            return ControlRoleDict.create();
 60→        }
 61→        return roleDict.clone();
 62→    }
