 64→    private ControlRoleDict loadRoleDict(Long userId, List<Long> spaceNodeIds) {
 65→        List<SpaceNodeUserRoleCacheEntity> entities = spaceNodeUserRoleCacheService.getByUserAndNodes(userId, spaceNodeIds);
 66→        ControlRoleDict dict = ControlRoleDict.create();
 67→        if (CollectionUtils.isEmpty(entities)) {
 68→            return dict;
 69→        }
 70→        for (SpaceNodeUserRoleCacheEntity entity : entities) {
 71→            if (entity == null || entity.getSpaceNodeId() == null || entity.getRoleLevel() == null) {
 72→                continue;
 73→            }
 74→            ControlRole role = NodeRoleLevel.fromLevel(entity.getRoleLevel()).toControlRole();
 75→            if (role == null) {
 76→                continue;
 77→            }
 78→            dict.put(entity.getSpaceNodeId().toString(), role);
 79→        }
 80→        return resetPermissionsBySpacePolicy(dict, spaceNodeIds);
 81→    }
