 83→    private ControlRoleDict resetPermissionsBySpacePolicy(ControlRoleDict dict, List<Long> spaceNodeIds) {
 84→        if (dict == null || dict.isEmpty()) {
 85→            return dict;
 86→        }
 87→        Map<String, List<Long>> spaceMap = spaceNodeQueryManager.getSpaceIdToSpaceNodeIdMap(spaceNodeIds);
 88→        Map<String, SpacePermissionPolicy> policyMap = spacePermissionPolicyQueryManager
 89→                .getPolicyMapBySpaceIdsCached(ControlType.SPACE_NODE.getVal(), spaceMap.keySet());
 90→        for (Map.Entry<String, List<Long>> entry : spaceMap.entrySet()) {
 91→            SpacePermissionPolicy policy = policyMap.get(entry.getKey());
 92→            List<Long> nodeIds = entry.getValue();
 93→            if (nodeIds == null) {
 94→                continue;
 95→            }
 96→            for (Long nodeId : nodeIds) {
 97→                ControlRole base = dict.get(nodeId.toString());
 98→                if (base == null) {
 99→                    continue;
100→                }
101→                dict.put(nodeId.toString(), new SpacePolicyEnforcedControlRole(base, policy));
102→            }
103→        }
104→        return dict;
105→    }
106→
107→    private String buildRoleCacheKey(Long userId, List<Long> spaceNodeIds) {
108→        StringBuilder idsPart = new StringBuilder();
109→        for (int i = 0; i < spaceNodeIds.size(); i++) {
110→            if (i > 0) {
111→                idsPart.append(',');
112→            }
113→            idsPart.append(spaceNodeIds.get(i));
114→        }
115→        return userId + "|" + idsPart;
116→    }
117→
118→    private List<Long> normalizeSpaceNodeIds(List<Long> spaceNodeIds) {
119→        Set<Long> deduplicated = new LinkedHashSet<>();
120→        for (Long spaceNodeId : spaceNodeIds) {
121→            if (spaceNodeId != null) {
122→                deduplicated.add(spaceNodeId);
123→            }
124→        }
125→        List<Long> normalized = new ArrayList<>(deduplicated);
126→        normalized.sort(Long::compareTo);
127→        return normalized;
128→    }
129→}
