 21→@Slf4j
 22→@Service
 23→public class SpaceNodeUserRoleCacheServiceImpl extends ServiceImpl<SpaceNodeUserRoleCacheMapper, SpaceNodeUserRoleCacheEntity> implements ISpaceNodeUserRoleCacheService {
 24→
 25→    @Override
 26→    public List<SpaceNodeUserRoleCacheEntity> getByUserAndNodes(Long userId, List<Long> nodeIds) {
 27→        return lambdaQuery()
 28→                .eq(SpaceNodeUserRoleCacheEntity::getUserId, userId)
 29→                .in(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, nodeIds)
 30→                .list();
 31→    }
 32→
 33→    @Override
 34→    public List<SpaceNodeUserRoleCacheEntity> getBySpaceAndNode(String spaceId, Long nodeId) {
 35→        return lambdaQuery()
 36→                .eq(SpaceNodeUserRoleCacheEntity::getSpaceId, spaceId)
 37→                .eq(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, nodeId)
 38→                .list();
 39→    }
 40→
 41→    @Override
 42→    public List<Long> listUserIdsByspaceNodeIdsAndMinRole(List<Long> spaceNodeIds, NodeRoleLevel minRole) {
 43→        if (CollectionUtils.isEmpty(spaceNodeIds) || minRole == null) {
 44→            return Collections.emptyList();
 45→        }
 46→        return lambdaQuery()
 47→                .in(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, spaceNodeIds)
 48→                .ge(SpaceNodeUserRoleCacheEntity::getRoleLevel, minRole.getLevel())
 49→                .list()
 50→                .stream()
 51→                .map(SpaceNodeUserRoleCacheEntity::getUserId)
 52→                .filter(Objects::nonNull)
 53→                .distinct()
 54→                .toList();
 55→    }
 56→
 57→    @Override
 58→    @Transactional
 59→    public List<SpaceNodeUserRoleCacheEntity> batchUpsert(List<SpaceNodeUserRoleCacheEntity> caches) {
 60→        if (caches == null || caches.isEmpty()) {
 61→            return new ArrayList<>();
 62→        }
 63→
 64→        // 按 uk_user_node(user_id, space_node_id) 去重，同 key 保留 roleLevel 较大的
 65→        List<SpaceNodeUserRoleCacheEntity> deduped = caches.stream()
 66→                .collect(Collectors.toMap(
 67→                        e -> e.getUserId() + "_" + e.getSpaceNodeId(),
 68→                        e -> e,
 69→                        (a, b) -> a.getRoleLevel() != null && (b.getRoleLevel() == null
 70→                                || a.getRoleLevel() >= b.getRoleLevel()) ? a : b
 71→                ))
 72→                .values().stream().toList();
 73→
 74→        List<SpaceNodeUserRoleCacheEntity> existingRecords = lambdaQuery()
 75→                .in(SpaceNodeUserRoleCacheEntity::getSpaceId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getSpaceId).distinct().collect(Collectors.toList()))
 76→                .in(SpaceNodeUserRoleCacheEntity::getUserId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getUserId).distinct().collect(Collectors.toList()))
 77→                .in(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getSpaceNodeId).distinct().collect(Collectors.toList()))
 78→                .list();
 79→
 80→        Map<String, SpaceNodeUserRoleCacheEntity> existingMap = existingRecords.stream()
 81→                .collect(Collectors.toMap(
 82→                        entity -> entity.getSpaceId() + "_" + entity.getUserId() + "_" + entity.getSpaceNodeId(),
 83→                        entity -> entity
 84→                ));
 85→
 86→        List<SpaceNodeUserRoleCacheEntity> toInsert = new ArrayList<>();
 87→        List<SpaceNodeUserRoleCacheEntity> toUpdate = new ArrayList<>();
 88→        List<SpaceNodeUserRoleCacheEntity> changed = new ArrayList<>();
 89→
 90→        for (SpaceNodeUserRoleCacheEntity cache : deduped) {
 91→            String key = cache.getSpaceId() + "_" + cache.getUserId() + "_" + cache.getSpaceNodeId();
 92→            SpaceNodeUserRoleCacheEntity existing = existingMap.get(key);
 93→
 94→            if (existing == null) {
 95→                if (cache.getRoleLevel() != null && cache.getRoleLevel() == 0) {
 96→                    continue;
 97→                }
 98→                toInsert.add(cache);
 99→                changed.add(cache);
100→            } else if (!existing.getRoleLevel().equals(cache.getRoleLevel())) {
101→                existing.setRoleLevel(cache.getRoleLevel());
102→                toUpdate.add(existing);
103→                changed.add(existing);
104→            }
105→        }
106→
107→        if (!toInsert.isEmpty()) {
108→            saveBatch(toInsert);
109→        }
110→
111→        if (!toUpdate.isEmpty()) {
112→            updateBatchById(toUpdate);
113→        }
114→
115→        return changed;
116→    }
117→}
