134→    @Override
135→    public NodeShareInfoVo readShareInfo(Long userId, String shareId) {
136→        NodeShareInfoVo infoVo = new NodeShareInfoVo();
137→        log.info("userId: {} try to redaShare: {}", userId, shareId);
138→        NodeShareEntity nodeShareEntity = nodeShareService.getByShareId(shareId);
139→
140→        if (nodeShareEntity == null) {
141→            infoVo.setErrorCode(1);
142→            infoVo.setErrorMsg("分享不存在");
143→            return infoVo;
144→        }
145→
146→        if (Boolean.FALSE.equals(nodeShareEntity.getIsEnabled())) {
147→            infoVo.setErrorCode(2);
148→            infoVo.setErrorMsg("分享未启用");
149→            return infoVo;
150→        }
151→
152→        SpaceNodeEntity spaceNodeEntity = spaceNodeService.getById(nodeShareEntity.getSpaceNodeId());
153→        if (spaceNodeEntity == null) {
154→            infoVo.setErrorCode(3);
155→            infoVo.setErrorMsg("文档被删除");
156→            return infoVo;
157→        }
158→
159→        String spaceId = spaceNodeEntity.getSpaceId();
160→        SpaceEntity spaceEntity = spaceService.getBySpaceId(spaceId);
161→        if (spaceEntity == null || spaceEntity.getIsForbid()) {
162→            infoVo.setErrorCode(4);
163→            infoVo.setErrorMsg("空间站被禁用");
164→            return infoVo;
165→        }
166→
167→        NodeShareProps props = NodeShareProps.fromBits(nodeShareEntity.getPropsBits());
168→        infoVo.setShareId(shareId);
169→        infoVo.setAllowSaved(props.getCanBeStored());
170→        infoVo.setAllowEdit(props.getCanBeEdited());
171→
172→        String email = null;
173→        boolean hasLogin = userId != null;
174→        if (hasLogin) {
175→            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
176→            email = user == null ? null : user.getEmail();
177→            ControlRoleDict controlRoleDict = controlTemplate.fetchSpaceNodeRole(userId, List.of(nodeShareEntity.getSpaceNodeId()));
178→            infoVo.setNodeRoles(controlRoleDict);
179→        }
180→        infoVo.setHasLogin(hasLogin);
181→
182→        ShareScopeEntity shareScope = shareScopeService.getByShareId(shareId);
183→        NodeShareScopeEntity nodeScope = nodeShareScopeService.getBySpaceNodeId(nodeShareEntity.getSpaceNodeId());
184→
185→        SpaceNodeTypeEnum spaceNodeType = SpaceNodeTypeEnum.fromValue(spaceNodeEntity.getType());
186→        boolean allowAnonymous = appSpaceNodeActionFactory.getSharable(spaceNodeType)
187→                .checkAllowAnonymous(new CheckAnonymousContext(shareId, spaceNodeEntity, shareScope, nodeScope));
188→
189→        if (!hasLogin && !allowAnonymous) {
190→            infoVo.setErrorCode(5);
191→            infoVo.setErrorMsg("请在登录后查看");
192→            return infoVo;
193→        }
194→
195→        boolean accessAllowed = checkAccess(shareScope, nodeScope, email, allowAnonymous);
196→        if (!accessAllowed) {
197→            infoVo.setErrorCode(6);
198→            infoVo.setErrorMsg("该用户未在被允许的分享范围内");
199→            return infoVo;
200→        }
201→
202→        LocalDateTime expireTime = nodeShareEntity.getExpireTime();
203→        if (expireTime != null && expireTime.isBefore(LocalDateTime.now())) {
204→            log.info("share expired, shareId={}, expireTime={}", shareId, expireTime);
205→            infoVo.setErrorCode(7);
206→            infoVo.setErrorMsg("分享已过期");
207→            return infoVo;
208→        }
209→
210→        NodeShareTreeVo rootTreeVo = new NodeShareTreeVo(nodeShareEntity);
211→
212→        infoVo.setSpaceId(spaceNodeEntity.getSpaceId());
213→        infoVo.setSpaceName(spaceEntity.getName());
214→        rootTreeVo.setAppSpaceNodeId(spaceNodeEntity.getAppSpaceNodeId());
215→        rootTreeVo.setSpaceNodeType(spaceNodeEntity.getType());
216→        rootTreeVo.setSpaceNodeName(spaceNodeEntity.getName());
217→
218→        boolean isFolderShare = ShareTypeEnum.GENERAL_FOLDER_NODE_SHARE.equals(ShareTypeEnum.fromValue(nodeShareEntity.getShareType()));
219→        if (isFolderShare) {
220→            populateFolderShareSubtree(rootTreeVo);
221→        }
222→
223→        infoVo.setNodeShare(rootTreeVo);
224→
225→        return infoVo;
226→    }
