 23→
 24→@EqualsAndHashCode(callSuper = true)
 25→@Data
 26→@Slf4j
 27→public class NodeControlRequest extends AbstractControlRequest {
 28→    private final List<Long> units;
 29→
 30→    private final List<Long> spaceNodeIds;
 31→
 32→    private boolean treeBuilding;
 33→
 34→    private boolean shareTreeBuilding;
 35→
 36→    private boolean rubbishBuilding;
 37→
 38→    private boolean internalBuilding;
 39→
 40→    public NodeControlRequest(List<Long> units, List<Long> spaceNodeIds) {
 41→        this.units = units;
 42→        this.spaceNodeIds = spaceNodeIds;
 43→    }
 44→
 45→    @Override
 46→    public ControlRoleDict execute() {
 47→        if (rubbishBuilding) {
 48→            log.info("Load Rubbish Node Permission");
 49→            return getRubbishNodeRoles();
 50→        }
 51→
 52→        List<SimpleNodeInfo> nodeList = getSimpleNodeInfos();
 53→        if (nodeList == null || nodeList.isEmpty()) {
 54→            return ControlRoleDict.create();
 55→        }
 56→
 57→        if (internalBuilding) {
 58→            log.info("Load Internal Node Permission");
 59→            return this.getInternalNodeRoles(nodeList);
 60→        }
 61→
 62→        // Use to find SimpleNodeInfo by spaceNodeId
 63→        Map<Long, SimpleNodeInfo> spaceNodeIdToSimpleNodeInfoMap = nodeList.stream()
 64→                .collect(Collectors.toMap(SimpleNodeInfo::getSpaceNodeId, node -> node));
 65→
 66→        // Find the upper-level path of the processing node (insert near-far in sequence),
 67→        // and determine the highest authority of the node
 68→        Map<Long, Set<Long>> parentNodeRoleMap = new LinkedHashMap<>(16);
 69→        // Collect all parent nodes with configuration roles in order to reduce circular query DB
 70→        // Query the roles of all parent nodes at one time,
 71→        // and use the collection traversal method to quickly calculate the permission roles of each node.
 72→        Set<Long> roleNodeIds = new HashSet<>();
 73→        // Start collecting the necessary attributes of nodes. There are two main elements for fast computing.
 74→        // 1.What is the permission mode of the node
 75→        // 2.If the node is in inheritance mode, the parent path has to be loaded, and the DB retrieval is also reduced
 76→        for (Long controlId : this.spaceNodeIds) {
 77→            // Find the node first
 78→            SimpleNodeInfo node = spaceNodeIdToSimpleNodeInfoMap.get(controlId);
 79→            // If the node information does not exist, look for the next one directly.
 80→            // It should exist, unless a deleted node is passed in.
 81→            if (node == null) {
 82→                log.warn("Node [{}] is not exist", controlId);
 83→                continue;
 84→            }
 85→            // If the permission of the node is to inherit the parent node,
 86→            // continue to look up to the parent directory.
 87→            // If the specified permission in the upper directory is not configured with itself, access is not allowed.
 88→            if (node.getExtend()) {
 89→                // Continue to look up to the parent directory. If the specified permissions in the parent directory are not configured with themselves, access is not allowed.
 90→                Set<Long> orderParentNodeIds = findParentNodeIdFromTop2Bottom(nodeList, node);
 91→                // Stores the ordered parent nodes of the specified node's superior corresponding to the specified mode.
 92→                // If it is the first-level node, it is an empty set
 93→                parentNodeRoleMap.put(controlId, orderParentNodeIds);
 94→                roleNodeIds.addAll(orderParentNodeIds);
 95→            }
 96→            else {
 97→                // The current node has set permissions, and directly obtains the permissions of the current node
 98→                roleNodeIds.add(controlId);
 99→            }
100→        }
101→
102→        if (roleNodeIds.isEmpty()) {
103→            // The parent nodes of all nodes have no permissions, or have no role permissions, return to the default permissions
104→            // This is generally the case in new space
105→            ControlRoleDict roleDict = ControlRoleDict.create();
106→            getControlIds().forEach(controlId -> roleDict.put(controlId, new DefaultWorkbenchRole()));
107→            return roleDict;
108→        }
109→
110→        // Find the role corresponding to the parent node at one time,
111→        // and use the algorithm to traverse to calculate the role configuration of each node
112→        List<ControlRoleEntity> controlRoles = SpringContextHolder.getBean(IControlRoleService.class).getByControlIds(roleNodeIds);
113→        // group by node
114→        Map<String, List<ControlRoleEntity>> nodeRoleMap = controlRoles.stream()
115→                .collect(Collectors.groupingBy(ControlRoleEntity::getControlId));
116→        Map<Long, Set<String>> nodeRoles = new LinkedHashMap<>(parentNodeRoleMap.size());
117→        // If the parent from top to bottom does not contain its own permissions, the following can no longer appear
118→        // The purpose of creating a SET collection to store unauthorized nodes is to avoid repeated comparisons and reduce traversal when a loop node encounters unauthorized access.
119→        Set<Long> accessDeniedNode = new HashSet<>();
120→        // Calculate the role of each node. For example, a node may have difference roles,
121→        // and the highest role can be taken according to the priority.
122→        for (Long controlId : this.spaceNodeIds) {
123→            // When building a node tree, the node is already in the filter list, skip it directly
124→            if (treeBuilding && accessDeniedNode.contains(controlId)) {
125→                continue;
126→            }
127→            // Determine what the permission mode of the current node is
128→            if (parentNodeRoleMap.containsKey(controlId)) {
129→                // Find if parent contains itself from top to bottom
130→                Set<Long> parentNodeIds = parentNodeRoleMap.get(controlId);
131→                if (parentNodeIds.isEmpty()) {
132→                    // The parent node of the node does not have permissions enabled, set the default role
133→                    nodeRoles.put(controlId, Set.of(SpaceNode.DEFAULT_ROLE));
134→                    continue;
135→                }
136→                // Parent nodes should be in order, from top to bottom, otherwise unimaginable data will definitely be generated
137→                int i = 0;
138→                for (Long parentNodeId : parentNodeIds) {
139→                    // If the parent node is unprivileged, all nodes below should also not be accessible
140→                    if (treeBuilding) {
141→                        if (accessDeniedNode.contains(parentNodeId)) {
142→                            continue;
143→                        }
144→                    }
145→                    // Categorize the roles the user has on the node, there may be multiple roles
146→                    Set<String> roles = calNodeRoles(nodeRoleMap, parentNodeId.toString(), getUnits());
147→                    if (roles.isEmpty()) {
148→                        // Found that the role configuration of a parent does not grant permission, which means that there is no permission,
149→                        // and directly filter out the following nodes
150→                        if (treeBuilding) {
151→                            List<Long> children = findAllChildren(nodeList, parentNodeId);
152→                            accessDeniedNode.addAll(children);
153→                            break;
154→                        }
155→                    }
156→                    else {
157→                        if (i == parentNodeIds.size() - 1) {
158→                            // Find the closest parent node
159→                            nodeRoles.put(controlId, roles);
160→                        }
161→                    }
162→                    i++;
163→                }
164→            }
165→            else {
166→                // If the node has set permissions, get the node permissions directly
167→                Set<String> roles = calNodeRoles(nodeRoleMap, controlId.toString(), getUnits());
168→                if (!roles.isEmpty()) {
169→                    nodeRoles.put(controlId, roles);
170→                }
171→                else if (treeBuilding) {
172→                    // When building node tree, directly filter out the following nodes
173→                    accessDeniedNode.add(controlId);
174→                    List<Long> children = findAllChildren(nodeList, controlId);
175→                    accessDeniedNode.addAll(children);
176→                }
177→            }
178→        }
179→        ControlRoleDict roleDict = ControlRoleDict.create();
180→        // Get the most privileged role
181→        nodeRoles.forEach((nodeId, roleCodes) -> roleDict.put(String.valueOf(nodeId), ControlRoleManager.getTopNodeRole(roleCodes)));
182→        return roleDict;
183→    }
