208→    public ControlRoleDict getRubbishNodeRoles() {
209→        ControlRoleDict roleDict = ControlRoleDict.create();
210→        // 删spaceNode时应该不会删对应ControlRole, 如果设置过这里能查到
211→        List<ControlRoleEntity> controlRoles = SpringContextHolder.getBean(IControlRoleService.class).getByControlIds(spaceNodeIds);
212→        if (controlRoles.isEmpty()) {
213→            // All nodes have no permissions. The node was previously inherited from the root node and returns to the default permissions.
214→            spaceNodeIds.forEach(controlId -> roleDict.put(controlId.toString(), new DefaultWorkbenchRole()));
215→            return roleDict;
216→        }
217→        // Get the node that has enabled permissions
218→        Set<String> enabledPermissionNodeIds = controlRoles.stream().map(ControlRoleEntity::getControlId).collect(Collectors.toSet());
219→        // Nodes without permissions, return to default permissions
220→        spaceNodeIds.stream().filter(nodeId -> !enabledPermissionNodeIds.contains(nodeId.toString()))
221→                .forEach(controlId -> roleDict.put(controlId.toString(), new DefaultWorkbenchRole()));
222→        // Filter organizational units and get role sets by node grouping
223→        Map<String, Set<String>> nodeRoles = controlRoles.stream()
224→                .filter(permission -> units.contains(permission.getUnitId()))
225→                .collect(Collectors.groupingBy(ControlRoleEntity::getControlId, Collectors.mapping(ControlRoleEntity::getRoleCode, Collectors.toSet())));
226→        if (nodeRoles.isEmpty()) {
227→            return roleDict;
228→        }
229→        // Get the most privileged role
230→        nodeRoles.forEach((nodeId, roleCodes) -> roleDict.put(nodeId, ControlRoleManager.getTopNodeRole(roleCodes)));
231→        return roleDict;
232→    }
233→
234→    /**
235→     * For internal call，Need to determine whether the node belongs to the ghost node
236→     * @param nodeList simple node list
237→     */
238→    private ControlRoleDict getInternalNodeRoles(List<SimpleNodeInfo> nodeList) {
239→        ControlRoleDict roleDict = ControlRoleDict.create();
240→        Map<Long, SimpleNodeInfo> nodeToInfoMap = nodeList.stream().collect(Collectors.toMap(SimpleNodeInfo::getSpaceNodeId, v -> v));
241→
242→        Map<Long, List<Long>> reverseParentNodeRoleMap = new LinkedHashMap<>(16);
243→        Set<Long> roleNodeIds = new HashSet<>();
244→        for (Long controlId : this.spaceNodeIds) {
245→            if (!nodeToInfoMap.containsKey(controlId)) {
246→                continue;
247→            }
248→            SimpleNodeInfo node = nodeToInfoMap.get(controlId);
249→            // If the node has set permissions, get the permissions of node directly
250→            if (!node.getExtend()) {
251→                roleNodeIds.add(controlId);
252→            }
253→            // Find all parent nodes from bottom to top
254→            List<Long> reverseParentNodeIds = findParentNodeIdFromBottom2Top(nodeList, node);
255→            reverseParentNodeRoleMap.put(controlId, reverseParentNodeIds);
256→            if (reverseParentNodeIds.isEmpty()) {
257→                continue;
258→            }
259→            roleNodeIds.addAll(reverseParentNodeIds);
260→        }
261→        // The parent nodes of all nodes have no permissions, and the current node has no permissions, returning to the default permissions
262→        if (roleNodeIds.isEmpty()) {
263→            getControlIds().forEach(controlId -> roleDict.put(controlId, new DefaultWorkbenchRole()));
264→            return roleDict;
265→        }
266→
267→        // Find the role corresponding to the parent node at one time, and use the algorithm to traverse to calculate the role configuration of each node
268→        List<ControlRoleEntity> controlRoles = SpringContextHolder.getBean(IControlRoleService.class).getByControlIds(roleNodeIds);
269→        // Group by node
270→        Map<String, List<ControlRoleEntity>> nodeRoleMap = controlRoles.stream()
271→                .collect(Collectors.groupingBy(ControlRoleEntity::getControlId));
272→
273→        for (Long controlId : this.spaceNodeIds) {
274→            if (!nodeToInfoMap.containsKey(controlId)) {
275→                continue;
276→            }
277→            SimpleNodeInfo node = nodeToInfoMap.get(controlId);
278→            Long nodeId = controlId;
279→            List<Long> reverseParentNodeIds = reverseParentNodeRoleMap.get(controlId);
280→            if (node.getExtend()) {
281→                if (reverseParentNodeIds.isEmpty()) {
282→                    // Set default roles
283→                    roleDict.put(controlId.toString(), new DefaultWorkbenchRole());
284→                    continue;
285→                }
286→                nodeId = reverseParentNodeIds.removeFirst();
287→            }
288→            // Compute node role
289→            Set<String> roles = calNodeRoles(nodeRoleMap, nodeId.toString(), getUnits());
290→            if (!roles.isEmpty()) {
291→                // Get the most privileged role
292→                roleDict.put(controlId.toString(), ControlRoleManager.getTopNodeRole(roles));
293→            } else {
294→                // No permission, not a ghost node
295→                continue;
296→            }
297→            // No upper-level nodes have designated permissions and should not be ghost nodes
298→            if (reverseParentNodeIds.isEmpty()) {
299→                continue;
300→            }
301→            // Query from bottom to top whether there is a superior node without permission, it should be a ghost node
302→            boolean isGhostNode = false;
303→            for (Long parentNodeId : reverseParentNodeIds) {
304→                Set<String> parentRoles = calNodeRoles(nodeRoleMap, parentNodeId.toString(), getUnits());
305→                if (parentRoles.isEmpty()) {
306→                    isGhostNode = true;
307→                    break;
308→                }
309→            }
310→
311→            NodeRole controlRole = (NodeRole) roleDict.get(controlId.toString());
312→            controlRole.setGhostNode(isGhostNode);
313→        }
314→        return roleDict;
315→    }
316→
317→    /**
318→     * Find parent nodes from top to bottom.
319→     * @param nodeList The list of nodes.
320→     * @param node The current node.
321→     * @return Set of parent spaceNode IDs from top to bottom.
322→     */
323→    private static Set<Long> findParentNodeIdFromTop2Bottom(List<SimpleNodeInfo> nodeList, SimpleNodeInfo node) {
324→        // Find parent node from bottom to top
325→        List<Long> parentNodeIds = findParentNodeIdFromBottom2Top(nodeList, node);
326→        // Reverse the order, because the acquisition is from bottom to top, for permission control, the order must be reversed, from top to bottom
327→        Collections.reverse(parentNodeIds);
328→        return new LinkedHashSet<>(parentNodeIds);
329→    }
330→
331→    /**
332→     * Find parent node IDs from bottom to top.
333→     * @param nodeList The list of nodes.
334→     * @param node The current node.
335→     * @return List of parent spaceNode IDs from bottom to top.
336→     */
337→    private static List<Long> findParentNodeIdFromBottom2Top(List<SimpleNodeInfo> nodeList, SimpleNodeInfo node) {
338→        // Find parent nodes in reverse order, from bottom to top
339→        List<Long> parents = new ArrayList<>();
340→        // Find all parent nodes with permissions configured, from bottom to top
341→        findParentNodeRole(nodeList, node, parents::add);
342→        return parents;
343→    }
344→
345→    /**
346→     * Recursively find parent nodes that have role permissions.
347→     * @param nodeList The list of nodes.
348→     * @param roleInfo The current node info.
349→     * @param parents The consumer to accept parent spaceNode IDs with permissions.
350→     */
351→    private static void findParentNodeRole(List<SimpleNodeInfo> nodeList, SimpleNodeInfo roleInfo, Consumer<Long> parents) {
352→        for (SimpleNodeInfo simpleNodeInfo : nodeList) {
353→            if (roleInfo.getParentId().equals(simpleNodeInfo.getNodeId())) {
354→                if (!simpleNodeInfo.getExtend()) {
355→                    parents.accept(simpleNodeInfo.getSpaceNodeId());
356→                }
357→                findParentNodeRole(nodeList, simpleNodeInfo, parents);
358→            }
359→        }
360→    }
361→
362→    /**
363→     * compute node role
364→     * @param nodeRoleMap Node role key-value pair
365→     * @param nodeId node id
366→     * @param memberUnitIds List of organizational units to which members belong
367→     * @return node role
368→     */
369→    private static Set<String> calNodeRoles(Map<String, List<ControlRoleEntity>> nodeRoleMap, String nodeId, List<Long> memberUnitIds) {
370→        List<ControlRoleEntity> permissions = nodeRoleMap.get(nodeId);
371→        if (permissions == null) {
372→            return new HashSet<>();
373→        }
374→        // The organizational unit corresponding to the node role
375→        Map<String, List<Long>> roleUnitMap = permissions.stream()
376→                .collect(Collectors.groupingBy(ControlRoleEntity::getRoleCode, Collectors.mapping(ControlRoleEntity::getUnitId, Collectors.toList())));
377→        return roleUnitMap.entrySet()
378→                .stream()
379→                .filter(entry -> memberUnitIds.stream().anyMatch(m -> entry.getValue().contains(m)))
380→                .map(Map.Entry::getKey).collect(Collectors.toSet());
381→    }
382→
383→    /**
384→     * Find all child nodes.
385→     * @param simpleNodeInfos List of node info.
386→     * @param parentSpaceNodeId Parent node spaceNodeId.
387→     * @return All child node spaceNodeIds.
388→     */
389→    private static List<Long> findAllChildren(List<SimpleNodeInfo> simpleNodeInfos, Long parentSpaceNodeId) {
390→        List<Long> allChildren = new ArrayList<>();
391→        List<Long> children = findChildren(simpleNodeInfos, parentSpaceNodeId);
392→        if (!children.isEmpty()) {
393→            allChildren.addAll(children);
394→            for (Long child : children) {
395→                List<Long> subs = findAllChildren(simpleNodeInfos, child);
396→                allChildren.addAll(subs);
397→            }
398→        }
399→        return allChildren;
400→    }
