 35→    @Override
 36→    @Transactional
 37→    public void saveOrUpdateControlRole(Long userId, String controlId, List<Long> unitIds, String role) {
 38→        Set<Long> insertUnitIds = new HashSet<>(unitIds);
 39→        List<ControlRoleEntity> controlRoles = getByControlId(controlId);
 40→        // exist -> update
 41→        controlRoles.forEach(controlRole -> {
 42→            Long unitId = controlRole.getUnitId();
 43→            if (insertUnitIds.contains(unitId)) {
 44→                controlRole.setRoleCode(role);
 45→                insertUnitIds.remove(unitId);
 46→            }
 47→        });
 48→        // not exist -> insert
 49→        insertUnitIds.forEach(unitId -> {
 50→            ControlRoleEntity controlRoleEntity = ControlRoleEntity.builder()
 51→                    .id(IdWorker.getId())
 52→                    .controlId(controlId)
 53→                    .unitId(unitId)
 54→                    .roleCode(role)
 55→                    .createdBy(userId)
 56→                    .updatedBy(userId)
 57→                    .build();
 58→            controlRoles.add(controlRoleEntity);
 59→        });
 60→
 61→        if (CollectionUtils.isNotEmpty(controlRoles)) {
 62→            saveOrUpdateBatch(controlRoles);
 63→        }
